/* Verificar remetente autorizado e extrair texto */
const body = $input.first().json;
const remetente = body.data?.key?.remoteJid || body.sender || '';
const autorizados = (process.env.RENATO_PHONE || '').split(',').concat((process.env.EQUIPE_PHONES || '').split(','));
const autorizado = autorizados.some(n => remetente.includes(n.replace('@c.us','')));
const texto = body.data?.message?.conversation || body.data?.message?.extendedTextMessage?.text || body.text || '';

return [{ json: { remetente, autorizado, texto, isAudio: !!body.data?.message?.audioMessage } }];

/* Preparar contexto completo para Claude — Notion AI style
 * Carregar memória + dados + histórico de conversa */
const metricas = $('Métricas').first().json;
const projetos = $('Projetos').first().json || [];
const memoria = $('Memória').first().json || {};
const pergunta = $('Verificar Remetente').first().json.texto;

// Resumo compacto dos projetos para o contexto
const resumo = (Array.isArray(projetos) ? projetos : []).map(p => (
  `#${p.numeroProjeto} ${p.clienteNome} | ${p.etapaAtual} | ${p.status} | ` +
  `Créditos: R$ ${(p.resultadosAuditoria?.totalCreditosIdentificados || 0).toLocaleString('pt-BR')} | ` +
  `Procuração: ${p.procuracao?.dataValidade || 'N/A'}`
)).join('\n');

// Histórico de conversa (últimas 10)
const historico = (memoria.conversaAtual?.mensagens || []).slice(-10);

return [{ json: { pergunta, metricas, resumoProjetos: resumo, historico, remetente: $('Verificar Remetente').first().json.remetente } }];

